// Command registration is now handled by command_factory.go
// This file only contains the run function implementation

// PersonaInfo represents persona information
type PersonaInfo struct {
	Name        string
	Roles       []string
	Description string
	Tags        []string
	Content     string
	FilePath    string
	// Source is either "library" or "project".
	Source string
}

// deprecatedPersonas lists personas from the pre-consolidation roster
// (pre-FEAT-011 Phase 3) that have been removed. The map is kept as empty
// to preserve the function signatures for future use if needed.
var deprecatedPersonas = map[string]string{}

// deprecationNoticeFor returns a human-readable warning string (without
// a newline) for a deprecated persona, or empty if the name is current.
// Callers write it to stderr themselves so the caller controls framing.
func deprecationNoticeFor(name string) string {
	replacement, deprecated := deprecatedPersonas[name]
	if !deprecated {
		return ""
	}
	if replacement != "" {
		return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release; use %q instead", name, replacement)
	}
	return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release with no direct replacement; see library/personas/README.md for the current 5-persona roster", name)
}

// PersonaMetadata represents parsed persona frontmatter
type PersonaMetadata struct {
	Name        string   `yaml:"name"`
	Roles       []string `yaml:"roles"`
	Description string   `yaml:"description"`
	Tags        []string `yaml:"tags"`
}

// PersonaBindings represents persona-role bindings
type PersonaBindings map[string]string

// PersonaStatus represents the status of active personas
type PersonaStatus struct {
	LoadedPersonas []string
	LoadedRoles    []string
	BindingsCount  int
	HasCLAUDEFile  bool
}

// =============================================================================
// CLI Interface Layer - Handles cobra.Command interactions and user output
// =============================================================================

// runPersona implements the persona command logic for CommandFactory
func (f *CommandFactory) runPersona(cmd *cobra.Command, args []string) error {
	return runPersonaWithWorkingDir(cmd, args, f.WorkingDir)
}

// runPersonaWithWorkingDir implements the persona command logic with working directory support
func runPersonaWithWorkingDir(cmd *cobra.Command, args []string, workingDir string) error {
	// Extract flags from cobra.Command
	listFlag, _ := cmd.Flags().GetBool("list")
	showFlag, _ := cmd.Flags().GetString("show")
	bindFlag, _ := cmd.Flags().GetString("bind")
	roleFlag, _ := cmd.Flags().GetString("role")
	roleFilter, _ := cmd.Flags().GetString("role")
	tagFilter, _ := cmd.Flags().GetString("tag")

	// Handle subcommands
	if len(args) > 0 {
		switch args[0] {
		case "list":
			personas, err := personaList(workingDir, roleFilter, tagFilter)
			if err != nil {
				return err
			}
			return displayPersonaList(cmd, personas)
		case "show":
			if len(args) < 2 {
				return fmt.Errorf("persona name required")
			}
			persona, err := personaShow(workingDir, args[1])
			if err != nil {
				return err
			}
			return displayPersona(cmd, persona)
		case "bind":
			if len(args) < 3 {
				return fmt.Errorf("role and persona name required")
			}
			err := personaBind(workingDir, args[1], args[2])
			if err != nil {
				return err
			}
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", args[1], args[2])
			return nil
		case "new":
			if len(args) < 2 {
				return fmt.Errorf("persona name required")
			}
			bodyFlag, _ := cmd.Flags().GetString("body")
			created, err := personaNew(workingDir, args[1], bodyFlag)
			if err != nil {
				return err
			}
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Created project persona '%s' at %s\n", created.Name, created.FilePath)
			return nil
		case "edit":
			if len(args) < 2 {
				return fmt.Errorf("persona name required")
			}
			bodyFlag, _ := cmd.Flags().GetString("body")
			updated, err := personaEdit(cmd, workingDir, args[1], bodyFlag)
			if err != nil {
				return err
			}
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Updated project persona '%s' at %s\n", updated.Name, updated.FilePath)
			return nil
		case "fork":
			if len(args) < 2 {
				return fmt.Errorf("persona name required")
			}
			asFlag, _ := cmd.Flags().GetString("as")
			forked, err := personaFork(workingDir, args[1], asFlag)
			if err != nil {
				return err
			}
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Forked library persona '%s' to project persona '%s' at %s\n", args[1], forked.Name, forked.FilePath)
			return nil
		case "delete":
			if len(args) < 2 {
				return fmt.Errorf("persona name required")
			}
			if err := personaDelete(workingDir, args[1]); err != nil {
				return err
			}
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Deleted project persona '%s'\n", args[1])
			return nil
		case "load":
			loadedPersonas, err := personaLoad(workingDir, args[1:]...)
			if err != nil {
				return err
			}
			return displayLoadResult(cmd, args[1:], loadedPersonas)
		case "bindings":
			bindings, err := personaBindings(workingDir)
			if err != nil {
				return err
			}
			return displayBindings(cmd, bindings)
		case "status":
			status, err := personaStatus(workingDir)
			if err != nil {
				return err
			}
			return displayPersonaStatus(cmd, status)
		}
	}

	// Handle flags
	if listFlag {
		personas, err := personaList(workingDir, roleFilter, tagFilter)
		if err != nil {
			return err
		}
		return displayPersonaList(cmd, personas)
	}

	if showFlag != "" {
		persona, err := personaShow(workingDir, showFlag)
		if err != nil {
			return err
		}
		return displayPersona(cmd, persona)
	}

	if bindFlag != "" && roleFlag != "" {
		err := personaBind(workingDir, roleFlag, bindFlag)
		if err != nil {
			return err
		}
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", roleFlag, bindFlag)
		return nil
	}

	// Show help when no flags or args provided
	return cmd.Help()
}

// displayPersonaList displays the list of personas to the user
func displayPersonaList(cmd *cobra.Command, personas []PersonaInfo) error {
	if len(personas) == 0 {
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No personas found")
		return nil
	}

	_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Available Personas:")
	_, _ = fmt.Fprintln(cmd.OutOrStdout())

package persona

import (
	"bufio"
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"gopkg.in/yaml.v3"
)

// PersonaLoaderImpl implements the PersonaLoader interface.
//
// A loader can own up to two source directories:
//   - libraryDir: read-only, shared across projects.
//   - projectDir: project-local (`.ddx/personas`). When a project persona has
//     the same name as a library persona, the project persona wins for that
//     project's bindings.
type PersonaLoaderImpl struct {
	// libraryDir is the legacy single directory and remains in use when the
	// loader is constructed via NewPersonaLoaderWithDir for test fixtures.
	personasDir string
	projectDir  string
}

// NewPersonaLoader creates a new persona loader rooted at the project's
// working directory. It discovers the library path from config and the
// project-local `.ddx/personas` directory.
func NewPersonaLoader(workingDir string) PersonaLoader {
	libraryDir := resolveLibraryPersonasDir(workingDir)
	projectDir := resolveProjectPersonasDir(workingDir)
	return NewPersonaLoaderWithDirs(libraryDir, projectDir)
}

// NewPersonaLoaderWithDir creates a new persona loader with a specific
// library directory. Kept for tests and back-compat callers that only need
// the library source.
func NewPersonaLoaderWithDir(dir string) PersonaLoader {
	return &PersonaLoaderImpl{
		personasDir: dir,
	}
}

// NewPersonaLoaderWithDirs creates a loader with explicit library and project
// directories. Either may be empty to disable that source.
func NewPersonaLoaderWithDirs(libraryDir, projectDir string) PersonaLoader {
	loader := NewPersonaLoaderWithDir(libraryDir).(*PersonaLoaderImpl)
	loader.projectDir = projectDir
	return loader
}

// resolveLibraryPersonasDir resolves the library persona directory.
func resolveLibraryPersonasDir(workingDir string) string {
	cfg, err := config.LoadWithWorkingDir(workingDir)
	if err != nil {
		_, _ = fmt.Fprintf(os.Stderr, "DDx config not found; run \"ddx init\" to bootstrap project\n")
		return ""
	}
	if cfg.Library == nil || cfg.Library.Path == "" {
		return ""
	}
	libPath := cfg.Library.Path
	if !filepath.IsAbs(libPath) && workingDir != "" {
		libPath = filepath.Join(workingDir, libPath)
	}
	return filepath.Join(libPath, "personas")
}

// resolveProjectPersonasDir returns the project-local persona directory.
func resolveProjectPersonasDir(workingDir string) string {
	if workingDir == "" {
		return ""
	}
	return filepath.Join(workingDir, ".ddx", "personas")
}

// LoadPersona loads a persona by name. Project-local personas override
// library personas with the same name.
func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
	if name == "" {
		return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
	}

	if l.projectDir != "" {
		candidate := filepath.Join(l.projectDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceProject)
		}
	}

	if l.personasDir != "" {
		candidate := filepath.Join(l.personasDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceLibrary)
		}
	}

	return nil, NewPersonaError(ErrorPersonaNotFound,
		fmt.Sprintf("persona '%s' not found", name), nil)
}

// readPersonaFile reads a single persona file and tags it with its source.
func readPersonaFile(filePath, source string) (*Persona, error) {
	content, err := os.ReadFile(filePath)
	if err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to read persona file %s", filePath), err)
	}
	if len(content) > MaxPersonaFileSize {
		return nil, NewPersonaError(ErrorValidation,
			fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", filePath, MaxPersonaFileSize), nil)
	}
	persona, err := parsePersona(content)
	if err != nil {
		return nil, NewPersonaError(ErrorInvalidPersona,
			fmt.Sprintf("failed to parse persona %s", filePath), err)
	}
	persona.Source = source
	persona.FilePath = filePath
	return persona, nil
}

// ListPersonas returns all available personas. Project personas override
// library personas of the same name; both sets are listed, with the project
// persona taking precedence when names collide.
func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
	// Project personas first so they win on collision.
	byName := map[string]*Persona{}
	var ordered []string

	for _, dir := range []struct {
		path   string
		source string
	}{
		{l.projectDir, SourceProject},
		{l.personasDir, SourceLibrary},
	} {
		if dir.path == "" || !dirExists(dir.path) {
			continue
		}
		entries, err := os.ReadDir(dir.path)
		if err != nil {
			return nil, NewPersonaError(ErrorFileOperation,
				fmt.Sprintf("failed to read personas directory %s", dir.path), err)
		}
		for _, entry := range entries {
			if entry.IsDir() {
				continue
			}
			if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
				continue
			}
			if entry.Name() == "README.md" || entry.Name() == "readme.md" {
				continue
			}
			personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
			if _, seen := byName[personaName]; seen {
				continue
			}
			persona, err := readPersonaFile(filepath.Join(dir.path, entry.Name()), dir.source)
			if err != nil {
				_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
				continue
			}
			byName[personaName] = persona
			ordered = append(ordered, personaName)
		}
	}

	result := make([]*Persona, 0, len(byName))
	for _, name := range ordered {
		result = append(result, byName[name])
	}
	return result, nil
}

